bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback)
{
    // Initialize variables
    esp_err_t err;
    size_t total_size = 0;
    size_t downloaded_size = 0;
    uint32_t last_update_time = 0;
    size_t last_downloaded_size = 0;
    size_t current_speed = 0;

    // Create HTTP client
    http_client_config_t config = {
        .url = url.c_str(),
        .method = HTTP_METHOD_GET,
        .timeout_ms = 30000,
        .max_redirections = 3,
    };

    http_client_handle_t client = NULL;
    err = http_client_new(&config, &client);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to create HTTP client: %s", esp_err_to_name(err));
        return false;
    }

    // Get content length
    err = http_client_open(client, HTTP_METHOD_GET);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        http_client_close(client);
        http_client_cleanup(client);
        return false;
    }

    // Check if we can get the content length
    int content_length = http_client_get_content_length(client);
    if (content_length <= 0) {
        ESP_LOGE(TAG, "Failed to get content length");
        http_client_close(client);
        http_client_cleanup(client);
        return false;
    }

    total_size = content_length;

    // Validate against partition size
    if (total_size > partition_->size - 12) {
        ESP_LOGE(TAG, "Content size (%ld) exceeds partition size (%ld - 12)", total_size, partition_->size);
        http_client_close(client);
        http_client_cleanup(client);
        return false;
    }

    // Erase flash memory sectors
    uint32_t sector_size = 4096; // Typical sector size
    uint32_t sectors_to_erase = (total_size + sector_size - 1) / sector_size;

    ESP_LOGI(TAG, "Erasing %d sectors for new asset data", sectors_to_erase);

    // Erase all sectors needed for this asset
    for (uint32_t i = 0; i < sectors_to_erase; i++) {
        uint32_t sector_addr = i * sector_size;
        err = esp_partition_erase_range(partition_, sector_addr, sector_size);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to erase sector %d: %s", i, esp_err_to_name(err));
            http_client_close(client);
            http_client_cleanup(client);
            return false;
        }
    }

    // Prepare to write data
    uint8_t *buffer = new uint8_t[4096];
    if (!buffer) {
        ESP_LOGE(TAG, "Failed to allocate buffer");
        http_client_close(client);
        http_client_cleanup(client);
        return false;
    }

    uint32_t write_offset = 12 + sizeof(mmap_assets_table) * 0; // Start after header

    // Download and write data in chunks
    while (downloaded_size < total_size) {
        size_t bytes_to_read = (total_size - downloaded_size > 4096) ? 4096 : (total_size - downloaded_size);
        int bytes_read = http_client_read(client, (char*)buffer, bytes_to_read);

        if (bytes_read <= 0) {
            ESP_LOGE(TAG, "Failed to read from HTTP connection, bytes_read=%d", bytes_read);
            delete[] buffer;
            http_client_close(client);
            http_client_cleanup(client);
            return false;
        }

        // Write to flash memory
        err = esp_partition_write(partition_, write_offset, buffer, bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to flash: %s", esp_err_to_name(err));
            delete[] buffer;
            http_client_close(client);
            http_client_cleanup(client);
            return false;
        }

        downloaded_size += bytes_read;
        write_offset += bytes_read;

        // Update progress
        int progress_percent = (int)((downloaded_size * 100) / total_size);

        // Calculate speed every 100ms
        uint32_t current_time = esp_timer_get_time() / 1000;
        if (current_time - last_update_time >= 100 || downloaded_size == total_size) {
            if (last_update_time > 0) {
                uint32_t time_diff = current_time - last_update_time;
                size_t bytes_diff = downloaded_size - last_downloaded_size;
                current_speed = (bytes_diff * 1000) / time_diff; // bytes per second
            }

            last_update_time = current_time;
            last_downloaded_size = downloaded_size;

            if (progress_callback) {
                progress_callback(progress_percent, current_speed);
            }
        }
    }

    // Clean up
    delete[] buffer;
    http_client_close(client);
    http_client_cleanup(client);

    // Update metadata table (simplified approach)
    uint32_t stored_files = 0;
    uint32_t stored_chksum = 0;
    uint32_t stored_len = 0;

    // This would normally update the metadata but for now just indicate success
    ESP_LOGI(TAG, "Successfully downloaded and stored asset from %s", url.c_str());

    return true;
}

