esp_err_t Ota::CheckVersion()
{
    std::string url = GetCheckVersionUrl();
    if (url.empty())
    {
        ESP_LOGE(TAG, "OTA URL is empty");
        return ESP_ERR_INVALID_ARG;
    }

    // Add trailing slash if needed
    if (url.back() != '/')
    {
        url += "/";
    }
    url += "check";

    auto http = SetupHttp();

    if (!http->Open("GET", url))
    {
        ESP_LOGE(TAG, "Failed to open HTTP connection");
        return ESP_FAIL;
    }

    auto status_code = http->GetStatusCode();
    if (status_code != 200)
    {
        ESP_LOGE(TAG, "Failed to check version, status code: %d", status_code);
        return ESP_FAIL;
    }

    std::string response = http->ReadAll();
    if (response.empty())
    {
        ESP_LOGE(TAG, "Empty response from OTA server");
        return ESP_FAIL;
    }

    ESP_LOGI(TAG, "OTA check response: %s", response.c_str());

    cJSON *json = cJSON_Parse(response.c_str());
    if (json == NULL)
    {
        ESP_LOGE(TAG, "Failed to parse JSON response");
        return ESP_FAIL;
    }

    // Parse firmware version
    cJSON *version = cJSON_GetObjectItem(json, "version");
    if (version && cJSON_IsString(version))
    {
        firmware_version_ = std::string(version->valuestring);
        ESP_LOGI(TAG, "Remote firmware version: %s", firmware_version_.c_str());
    }

    // Parse firmware URL
    cJSON *firmware_url = cJSON_GetObjectItem(json, "url");
    if (firmware_url && cJSON_IsString(firmware_url))
    {
        firmware_url_ = std::string(firmware_url->valuestring);
        ESP_LOGI(TAG, "Firmware URL: %s", firmware_url_.c_str());
    }

    // Parse activation code if present
    cJSON *activation_code = cJSON_GetObjectItem(json, "activation_code");
    if (activation_code && cJSON_IsString(activation_code))
    {
        activation_code_ = std::string(activation_code->valuestring);
        has_activation_code_ = true;
        ESP_LOGI(TAG, "Activation code received: %s", activation_code_.c_str());
    }
    else
    {
        has_activation_code_ = false;
    }

    // Parse activation challenge if present
    cJSON *activation_challenge = cJSON_GetObjectItem(json, "activation_challenge");
    if (activation_challenge && cJSON_IsString(activation_challenge))
    {
        activation_challenge_ = std::string(activation_challenge->valuestring);
        has_activation_challenge_ = true;
        ESP_LOGI(TAG, "Activation challenge received");
    }
    else
    {
        has_activation_challenge_ = false;
    }

    // Parse MQTT configuration if present
    cJSON *mqtt_config = cJSON_GetObjectItem(json, "mqtt");
    if (mqtt_config && cJSON_IsObject(mqtt_config))
    {
        cJSON *mqtt_server = cJSON_GetObjectItem(mqtt_config, "server");
        if (mqtt_server && cJSON_IsString(mqtt_server))
        {
            mqtt_server_ = std::string(mqtt_server->valuestring);
            has_mqtt_config_ = true;
            ESP_LOGI(TAG, "MQTT server: %s", mqtt_server_.c_str());
        }

        cJSON *mqtt_port = cJSON_GetObjectItem(mqtt_config, "port");
        if (mqtt_port && cJSON_IsNumber(mqtt_port))
        {
            mqtt_port_ = mqtt_port->valueint;
            ESP_LOGI(TAG, "MQTT port: %d", mqtt_port_);
        }
    }

    // Check if new version is available
    auto current_version = esp_app_get_description()->version;
    ESP_LOGI(TAG, "Current version: %s", current_version);

    if (!firmware_version_.empty() && IsNewVersionAvailable(current_version, firmware_version_))
    {
        has_new_version_ = true;
        ESP_LOGI(TAG, "New version available: %s", firmware_version_.c_str());
    }
    else
    {
        has_new_version_ = false;
        ESP_LOGI(TAG, "No new version available");
    }

    cJSON_Delete(json);
    return ESP_OK;
}

