void Ota::MarkCurrentVersionValid()
{
    // Get the currently running partition
    const esp_partition_t *running_partition = esp_ota_get_running_partition();
    if (running_partition == NULL)
    {
        ESP_LOGE(TAG, "Failed to get running partition");
        return;
    }

    // Skip validation for factory partition
    if (strcmp(running_partition->label, "factory") == 0)
    {
        ESP_LOGI(TAG, "Skipping validation for factory partition");
        return;
    }

    // Check if the current partition is in a pending verification state
    // We can check this by looking at the OTA state of the running partition
    esp_ota_state_t ota_state;
    esp_err_t err = esp_ota_get_state_partition(running_partition, &ota_state);
    if (err != ESP_OK)
    {
        ESP_LOGW(TAG, "Failed to get OTA state for partition %s: %s", running_partition->label, esp_err_to_name(err));
        return;
    }

    ESP_LOGI(TAG, "Current partition %s OTA state: %d", running_partition->label, ota_state);

    // Only mark as valid if it's in PENDING_VERIFY state
    if (ota_state == ESP_OTA_STATE_PENDING_VERIFY)
    {
        ESP_LOGI(TAG, "Marking partition %s as valid", running_partition->label);

        // Mark the current partition as valid
        err = esp_ota_mark_app_valid_cancel_rollback();
        if (err != ESP_OK)
        {
            ESP_LOGE(TAG, "Failed to mark partition %s as valid: %s", running_partition->label, esp_err_to_name(err));
            return;
        }

        ESP_LOGI(TAG, "Successfully marked partition %s as valid", running_partition->label);
    }
    else if (ota_state == ESP_OTA_STATE_VALID)
    {
        ESP_LOGI(TAG, "Partition %s is already valid", running_partition->label);
    }
    else
    {
        ESP_LOGI(TAG, "Partition %s is in state %d, skipping validation", running_partition->label, ota_state);
    }
}

