{
    ESP_LOGI(TAG, "Starting OTA upgrade from URL: %s", firmware_url.c_str());

    // Validate URL
    if (firmware_url.empty()) {
        ESP_LOGE(TAG, "Invalid firmware URL");
        return false;
    }

    // Setup HTTP connection
    auto http = SetupHttp();
    if (!http) {
        ESP_LOGE(TAG, "Failed to setup HTTP connection");
        return false;
    }

    // Open HTTP connection for download
    if (!http->Open("GET", firmware_url)) {
        int last_error = http->GetLastError();
        ESP_LOGE(TAG, "Failed to open HTTP connection for download, code=0x%x", last_error);
        return false;
    }

    // Get content length for progress calculation
    size_t content_length = http->GetContentLength();
    if (content_length == 0) {
        ESP_LOGW(TAG, "Could not determine content length, downloading without progress tracking");
    }

    // Get OTA partition
    const esp_partition_t *ota_partition = esp_ota_get_next_update_partition(NULL);
    if (ota_partition == NULL) {
        ESP_LOGE(TAG, "Failed to get OTA partition");
        http->Close();
        return false;
    }

    ESP_LOGI(TAG, "Writing to OTA partition: %s", ota_partition->label);

    // Start OTA write
    esp_ota_handle_t ota_handle;
    esp_err_t err = esp_ota_begin(ota_partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to start OTA, err=0x%x", err);
        http->Close();
        return false;
    }

    // Download and write firmware
    const size_t buffer_size = 4096;
    std::vector<uint8_t> buffer(buffer_size);
    size_t total_written = 0;
    size_t last_reported_bytes = 0;
    uint64_t last_time = esp_timer_get_time();

    while (true) {
        ssize_t bytes_read = http->Read(buffer.data(), buffer_size);
        if (bytes_read <= 0) {
            break;
        }

        // Write to OTA partition
        err = esp_ota_write(ota_handle, buffer.data(), bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write OTA data, err=0x%x", err);
            esp_ota_end(ota_handle);
            http->Close();
            return false;
        }

        total_written += bytes_read;

        // Calculate speed and report progress
        if (callback && (content_length > 0 || total_written - last_reported_bytes >= 1024)) {
            uint64_t current_time = esp_timer_get_time();
            uint64_t time_diff_us = current_time - last_time;

            size_t speed = 0;
            if (time_diff_us > 0) {
                // Convert microseconds to seconds and calculate bytes per second
                speed = static_cast<size_t>((total_written - last_reported_bytes) * 1000000.0 / time_diff_us);
            }

            int progress = 0;
            if (content_length > 0) {
                progress = static_cast<int>((total_written * 100) / content_length);
            }

            callback(progress, speed);

            last_reported_bytes = total_written;
            last_time = current_time;
        }
    }

    // Close HTTP connection
    http->Close();

    // Finalize OTA write
    err = esp_ota_end(ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to end OTA, err=0x%x", err);
        return false;
    }

    // Set OTA partition as boot partition
    err = esp_ota_set_boot_partition(ota_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to set boot partition, err=0x%x", err);
        return false;
    }

    ESP_LOGI(TAG, "OTA upgrade completed successfully");

    // Report final progress
    if (callback) {
        callback(100, 0);
    }

    return true;
}

