std::vector<int> Ota::ParseVersion(const std::string &version)
{
    std::vector<int> result;

    // Handle empty string
    if (version.empty()) {
        return result;
    }

    // Split the version string by dots
    std::stringstream ss(version);
    std::string component;

    while (std::getline(ss, component, '.')) {
        // Validate that component is not empty
        if (component.empty()) {
            return {}; // Return empty vector on invalid input
        }

        // Check if all characters are digits
        bool isValid = true;
        for (char c : component) {
            if (!std::isdigit(c)) {
                isValid = false;
                break;
            }
        }

        if (!isValid) {
            return {}; // Return empty vector on invalid component
        }

        // Convert to integer and add to result
        try {
            int num = std::stoi(component);
            result.push_back(num);
        } catch (const std::exception&) {
            return {}; // Return empty vector on conversion error
        }
    }

    return result;
}

