bool Ota::IsNewVersionAvailable(const std::string& currentVersion, const std::string& newVersion) {
    // Parse both version strings into vectors of integers
    std::vector<int> currentVersions = ParseVersion(currentVersion);
    std::vector<int> newVersions = ParseVersion(newVersion);

    // Compare version segments one by one
    size_t minSize = std::min(currentVersions.size(), newVersions.size());

    for (size_t i = 0; i < minSize; ++i) {
        if (newVersions[i] > currentVersions[i]) {
            return true;  // New version is greater
        }
        if (newVersions[i] < currentVersions[i]) {
            return false; // New version is smaller
        }
        // If equal, continue to next segment
    }

    // If we've reached here, all compared segments were equal
    // Check if new version has more segments (e.g., 1.2.3.4 vs 1.2.3)
    return newVersions.size() > currentVersions.size();
}

