std::string Ota::GetActivationPayload()
{
    // If no serial number is available, return empty JSON object
    if (!has_serial_number_) {
        return "{}";
    }

    // Create JSON payload
    cJSON *root = cJSON_CreateObject();
    if (root == NULL) {
        return "{}";
    }

    // Add serial number
    cJSON_AddStringToObject(root, "serial_number", serial_number_.c_str());

    // Add challenge string
    cJSON_AddStringToObject(root, "challenge", activation_challenge_.c_str());

    // Generate HMAC-SHA256 signature
    std::string payload_to_sign = serial_number_ + activation_challenge_;

#ifdef SOC_HMAC_SUPPORTED
    // Use hardware-backed HMAC key for signing
    uint8_t hmac_result[32]; // SHA256 produces 32 bytes

    // Get the HMAC key from efuse (assuming it's stored in a specific efuse field)
    // This is a simplified approach - in practice, you'd need to determine the correct efuse field
    esp_err_t err = esp_hmac_calculate(ESP_HMAC_SHA256, 
                                       (const uint8_t*)payload_to_sign.c_str(),
                                       payload_to_sign.length(),
                                       (uint8_t*)"device_activation_key", // This should be replaced with actual key from efuse
                                       21, // Length of the key
                                       hmac_result);

    if (err == ESP_OK) {
        // Convert HMAC result to hex string
        std::string signature;
        signature.reserve(64);
        for (int i = 0; i < 32; i++) {
            char hex[3];
            snprintf(hex, sizeof(hex), "%02x", hmac_result[i]);
            signature += hex;
        }
        cJSON_AddStringToObject(root, "signature", signature.c_str());
    } else {
        ESP_LOGE(TAG, "Failed to calculate HMAC: %s", esp_err_to_name(err));
        cJSON_Delete(root);
        return "{}";
    }
#else
    // Fallback for platforms without HMAC support
    ESP_LOGW(TAG, "HMAC not supported on this platform");
    cJSON_Delete(root);
    return "{}";
#endif

    // Convert JSON to string
    char *json_string = cJSON_Print(root);
    if (json_string == NULL) {
        cJSON_Delete(root);
        return "{}";
    }

    std::string result = json_string;
    cJSON_Delete(root);
    free(json_string);

    return result;
}

