size_t SystemInfo::GetFlashSize() {
    size_t flash_size = 0;
    esp_flash_t* flash = NULL;

    // Get the default flash chip handle
    esp_err_t err = esp_flash_init(&flash);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to initialize flash: %s", esp_err_to_name(err));
        return 0;
    }

    // Get the flash size
    err = esp_flash_get_size(flash, &flash_size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to get flash size: %s", esp_err_to_name(err));
        return 0;
    }

    return flash_size;
}

