std::string SystemInfo::GetUserAgent() {
    // Get the application descriptor to retrieve firmware version
    const esp_app_desc_t* app_desc = esp_app_get_description();
    if (app_desc == nullptr) {
        // Fallback to chip model name if app description is not available
        return GetChipModelName() + "/unknown";
    }

