    // Get the current tick count before starting the measurement
    TickType_t start_tick = xTaskGetTickCount();

    // Initialize arrays to store task statistics
    TaskHandle_t *pxTaskHandles = NULL;
    UBaseType_t uxArraySize = 0;
    uint32_t *pulTaskRunTimeStart = NULL;
    uint32_t *pulTaskRunTimeEnd = NULL;
    char *pcTaskName = NULL;

    // Get the number of tasks
    uxArraySize = uxTaskGetNumberOfTasks();

    // Allocate memory for task handles and run time arrays
    pxTaskHandles = (TaskHandle_t*)malloc(uxArraySize * sizeof(TaskHandle_t));
    pulTaskRunTimeStart = (uint32_t*)malloc(uxArraySize * sizeof(uint32_t));
    pulTaskRunTimeEnd = (uint32_t*)malloc(uxArraySize * sizeof(uint32_t));
    pcTaskName = (char*)malloc(32); // Max task name length

    if (!pxTaskHandles || !pulTaskRunTimeStart || !pulTaskRunTimeEnd || !pcTaskName) {
        ESP_LOGE(TAG, "Failed to allocate memory for task statistics");
        free(pxTaskHandles);
        free(pulTaskRunTimeStart);
        free(pulTaskRunTimeEnd);
        free(pcTaskName);
        return ESP_FAIL;
    }

    // Collect initial task run-time statistics
    uxArraySize = uxTaskGetSystemState(pxTaskHandles, uxArraySize, NULL);

    // Fill in the run-time statistics for each task
    for (UBaseType_t i = 0; i < uxArraySize; i++) {
        pulTaskRunTimeStart[i] = pcTaskGetRunTimeCounter(pxTaskHandles[i]);
    }

    // Wait for the specified time interval
    vTaskDelay(xTicksToWait);

    // Collect final task run-time statistics
    uxArraySize = uxTaskGetSystemState(pxTaskHandles, uxArraySize, NULL);

    // Fill in the final run-time statistics for each task
    for (UBaseType_t i = 0; i < uxArraySize; i++) {
        pulTaskRunTimeEnd[i] = pcTaskGetRunTimeCounter(pxTaskHandles[i]);
    }

    // Calculate and display CPU usage for each task
    ESP_LOGI(TAG, "Task CPU Usage Report:");
    ESP_LOGI(TAG, "Task Name           | CPU Usage (%)");
    ESP_LOGI(TAG, "-------------------|--------------");

    // Calculate total run time for all tasks during the interval
    uint32_t total_run_time = 0;
    for (UBaseType_t i = 0; i < uxArraySize; i++) {
        total_run_time += (pulTaskRunTimeEnd[i] - pulTaskRunTimeStart[i]);
    }

    // Calculate individual task CPU usage
    for (UBaseType_t i = 0; i < uxArraySize; i++) {
        uint32_t run_time_delta = pulTaskRunTimeEnd[i] - pulTaskRunTimeStart[i];

        // Calculate percentage of CPU time used
        float cpu_usage_percent = 0.0f;
        if (total_run_time > 0) {
            cpu_usage_percent = (float)(run_time_delta * 100.0f) / (float)total_run_time;
        }

        // Get task name
        const char* task_name = pcTaskGetName(pxTaskHandles[i]);
        if (task_name == NULL) {
            task_name = "Unknown";
        }

        // Print task CPU usage
        ESP_LOGI(TAG, "%-18s | %.2f%%", task_name, cpu_usage_percent);
    }

    // Free allocated memory
    free(pxTaskHandles);
    free(pulTaskRunTimeStart);
    free(pulTaskRunTimeEnd);
    free(pcTaskName);

    return ESP_OK;
}

