    // Allocate buffer for task list
    pcWriteBuffer = (char*)malloc(xFreeBytesRemaining);
    if (pcWriteBuffer == NULL) {
        ESP_LOGE(TAG, "Failed to allocate memory for task list");
        return;
    }

    // Get the actual task list
    vTaskList(pcWriteBuffer, xFreeBytesRemaining);

    // Log the task list
    ESP_LOGI(TAG, "Task List:\n%s", pcWriteBuffer);

    // Free allocated memory
    free(pcWriteBuffer);
}

