void AudioCodec::SetOutputVolume(int volume) {
    // Initialize and validate the input volume parameter
    if (volume < 0) {
        volume = 0;
        ESP_LOGW(TAG, "Output volume value (%d) is negative, clamping to 0", volume);
    } else if (volume > 100) {
        volume = 100;
        ESP_LOGW(TAG, "Output volume value (%d) exceeds maximum, clamping to 100", volume);
    }

    // Update the internal audio codec volume state
    output_volume_ = volume;

    // Persist the updated volume setting to non-volatile storage
    Settings settings("audio", true);  // true indicates we want to write changes
    settings.SetInt("output_volume", output_volume_);

    // Log the volume change for debugging and monitoring
    ESP_LOGI(TAG, "Set output volume to %d", output_volume_);
}

