void AudioCodec::SetInputGain(float gain) {
    // Validate input gain parameter to ensure it falls within acceptable audio processing ranges
    if (gain < 0.0f) {
        ESP_LOGW(TAG, "Input gain value (%.2f) is negative, clamping to 0.0", gain);
        gain = 0.0f;
    } else if (gain > 1.0f) {
        ESP_LOGW(TAG, "Input gain value (%.2f) exceeds maximum, clamping to 1.0", gain);
        gain = 1.0f;
    }

    // Update the internal gain setting of the audio codec using the validated gain value
    input_gain_ = gain;

    // Log the gain change for debugging and monitoring purposes
    ESP_LOGI(TAG, "Set input gain to %.2f", input_gain_);

    // Save to settings for persistence (similar to SetOutputVolume)
    Settings settings("audio", true);
    settings.SetFloat("input_gain", input_gain_);
}

