void Es8388AudioCodec::SetOutputVolume(int volume) {
    // Validate the input volume level to ensure it is within acceptable hardware limits
    if (volume < 0) {
        volume = 0;
    } else if (volume > 100) {
        volume = 100;
    }

    // Update the internal volume state variable with the new volume level
    output_volume_ = volume;

    // Convert volume percentage to hardware register value
    // ES8388 volume range is typically 0-63 (0dB = 30, -45dB = 0)
    // Map 0-100% to 0-63 range
    uint8_t reg_value = (uint8_t)((volume * 63) / 100);

    // Ensure minimum volume level (avoid completely muted)
    if (reg_value == 0 && volume > 0) {
        reg_value = 1;
    }

    // Write the new volume setting to the ES8388 hardware registers via I2C
    uint8_t regs[] = { 46, 47, 48, 49 }; // HP_LVOL, HP_RVOL, SPK_LVOL, SPK_RVOL
    for (uint8_t reg : regs) {
        ctrl_if_->write_reg(ctrl_if_, reg, 1, &reg_value, 1);
    }

    // Synchronize software and hardware volume states to prevent drift
    // This is already handled by updating the internal state and writing to hardware
}

