void AfeWakeWord::AudioDetectionTask()
{
    ESP_LOGI(TAG, "Audio detection task started");

    while (true)
    {
        // Wait for detection to be started
        EventBits_t bits = xEventGroupWaitBits(event_group_, 
                                              DETECTION_RUNNING_EVENT, 
                                              pdFALSE, 
                                              pdFALSE, 
                                              portMAX_DELAY);

        if (bits & DETECTION_RUNNING_EVENT)
        {
            // Check if we have valid AFE data
            if (afe_data_ == nullptr)
            {
                vTaskDelay(pdMS_TO_TICKS(100));
                continue;
            }

            // Process audio frames
            int16_t *afe_buffer = nullptr;
            size_t buffer_size = afe_iface_->get_feed_chunksize(afe_data_);

            if (buffer_size == 0)
            {
                vTaskDelay(pdMS_TO_TICKS(10));
                continue;
            }

            // Allocate buffer for audio data
            afe_buffer = new int16_t[buffer_size];
            if (afe_buffer == nullptr)
            {
                vTaskDelay(pdMS_TO_TICKS(10));
                continue;
            }

            // Get audio data from AFE
            int ret = afe_iface_->fetch(afe_data_, afe_buffer);
            if (ret != ESP_OK)
            {
                delete[] afe_buffer;
                vTaskDelay(pdMS_TO_TICKS(10));
                continue;
            }

            // Detect wake word
            int wake_word_index = afe_iface_->detect(afe_data_);

            if (wake_word_index >= 0 && wake_word_index < static_cast<int>(wake_words_.size()))
            {
                // Wake word detected
                std::string detected_wake_word = wake_words_[wake_word_index];

                ESP_LOGI(TAG, "Wake word '%s' detected", detected_wake_word.c_str());

                // Store the audio data
                StoreWakeWordData(afe_buffer, buffer_size);

                // Stop detection
                Stop();

                // Trigger callback
                if (wake_word_detected_callback_)
                {
                    wake_word_detected_callback_(detected_wake_word);
                }

                // Set the last detected wake word
                last_detected_wake_word_ = detected_wake_word;

                // Reset the buffer after detection
                afe_iface_->reset_buffer(afe_data_);
            }
            else
            {
                // No wake word detected, but still store data for potential future encoding
                StoreWakeWordData(afe_buffer, buffer_size);
            }

            delete[] afe_buffer;
        }

        // Small delay to prevent excessive CPU usage
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

