{
    // Calculate how many samples constitute 2 seconds of audio at 16kHz
    const size_t max_samples = 2 * 16000; // 2 seconds at 16kHz

    // Lock the mutex to protect concurrent access
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Add new samples to our buffer
    wake_word_pcm_.emplace_back(std::vector<int16_t>(data, data + samples));

    // If we have more than 2 seconds worth of data, remove the oldest segments
