void AfeWakeWord::EncodeWakeWordData()
{
    // Create a new task for encoding wake word data
    wake_word_encode_task_buffer_ = (StaticTask_t*)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_SPIRAM);
    if (wake_word_encode_task_buffer_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to allocate memory for task buffer");
        return;
    }

    wake_word_encode_task_stack_ = (StackType_t*)heap_caps_malloc(4096, MALLOC_CAP_SPIRAM);
    if (wake_word_encode_task_stack_ == nullptr)
    {
        ESP_LOGE(TAG, "Failed to allocate memory for task stack");
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_buffer_ = nullptr;
        return;
    }

    // Create the encoding task
    wake_word_encode_task_ = xTaskCreateStatic([](void *arg)
    {
        auto this_ = (AfeWakeWord*)arg;

        // Initialize Opus encoder with low complexity settings
        OpusEncoder *encoder = opus_encoder_create(16000, 1, OPUS_APPLICATION_VOIP, NULL);
        if (encoder == NULL)
        {
            ESP_LOGE(TAG, "Failed to create Opus encoder");
            return;
        }

        // Set encoder to low complexity mode for fast encoding
        opus_encoder_ctl(encoder, OPUS_SET_COMPLEXITY(0));

        // Process PCM data and encode to Opus
        while (true)
        {
            // Wait for PCM data to be available
            std::unique_lock<std::mutex> lock(this_->wake_word_mutex_);
            this_->wake_word_cv_.wait(lock, [this_]()
            {
                return !this_->wake_word_pcm_.empty();
            });

            // Process all available PCM data
            while (!this_->wake_word_pcm_.empty())
            {
                // Get the first PCM packet
                auto pcm_packet = this_->wake_word_pcm_.front();
                this_->wake_word_pcm_.pop_front();

                // Encode PCM to Opus
                const int opus_frame_size = 160; // 10ms at 16kHz
                const int max_opus_bytes = 1000; // Maximum expected Opus packet size

                std::vector<uint8_t> opus_packet(max_opus_bytes);
                int opus_len = opus_encode(encoder, pcm_packet.data(), 
                                          pcm_packet.size() / 2, // Convert sample count to frame count
                                          opus_packet.data(), max_opus_bytes);

                if (opus_len > 0)
                {
                    // Resize to actual encoded size
                    opus_packet.resize(opus_len);

                    // Store in thread-safe buffer
                    std::lock_guard<std::mutex> lock(this_->wake_word_mutex_);
                    this_->wake_word_opus_.push_back(std::move(opus_packet));

                    // Notify waiting consumers
                    this_->wake_word_cv_.notify_one();
                }
            }
        }

        // Cleanup
        opus_encoder_destroy(encoder);

    }, "wake_word_encode", 4096, this, 3, wake_word_encode_task_stack_, wake_word_encode_task_buffer_);

    if (wake_word_encode_task_ == NULL)
    {
        ESP_LOGE(TAG, "Failed to create wake word encode task");
        heap_caps_free(wake_word_encode_task_stack_);
        heap_caps_free(wake_word_encode_task_buffer_);
        wake_word_encode_task_stack_ = nullptr;
        wake_word_encode_task_buffer_ = nullptr;
        return;
    }
}

