bool AfeWakeWord::GetWakeWordOpus(std::vector<uint8_t>& opus) {
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until there's data available in the queue
    wake_word_cv_.wait(lock, [this]() {
        return !wake_word_opus_.empty();
    });

    // Retrieve the next Opus-encoded data
    if (!wake_word_opus_.empty()) {
        opus = std::move(wake_word_opus_.front());
        wake_word_opus_.pop_front();

        // Check if this is the sentinel value (empty vector) indicating completion
        if (opus.empty()) {
            // This indicates the encoding is complete, but we still return true
            // as we successfully retrieved data
            return true;
        }

        return true;
    }

    return false;
}

