size_t CustomWakeWord::GetFeedSize() {
    // Check if the model is initialized
    if (multinet_model_data_ == nullptr) {
        return 0;
    }

    // Return the required audio sample chunk size for the wake word detection model
    // This is typically the number of samples per frame that the model expects
    // Based on common ESP-MN configurations and the comment in Feed() method,
    // the duration is 30ms with 16000Hz sample rate = 480 samples
    // But we should get this from the model itself
    if (multinet_ != nullptr && multinet_model_data_ != nullptr) {
        // Get the frame size from the multinet model
        // This is typically the number of samples needed for one inference
        return multinet_->get_frame_size(multinet_model_data_);
    }

    // Fallback to a reasonable default if we can't get the frame size
    // Common values for wake word detection are around 512 samples (32ms at 16kHz)
    return 512;
}

