void CustomWakeWord::StoreWakeWordData(const std::vector<int16_t>& data) {
    // Lock the mutex for thread safety
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Add the new data to our buffer
    wake_word_pcm_.push_back(data);

    // Calculate approximate number of samples in the buffer
    // Assuming 16kHz sample rate, 2 seconds = 32000 samples
    const size_t max_samples = 32000;
    size_t total_samples = 0;

    // Count total samples in current buffer
    for (const auto& chunk : wake_word_pcm_) {
        total_samples += chunk.size();
    }

    // If we exceed the 2-second window, remove oldest chunks
    while (total_samples > max_samples && !wake_word_pcm_.empty()) {
        // Remove the first chunk (oldest)
        total_samples -= wake_word_pcm_.front().size();
        wake_word_pcm_.pop_front();
    }
}

