bool CustomWakeWord::GetWakeWordOpus(std::vector<uint8_t> &opus)
{
    std::unique_lock<std::mutex> lock(wake_word_mutex_);

    // Wait until there's data available in the queue
    wake_word_cv_.wait(lock, [this] { return !wake_word_opus_.empty(); });

    // Retrieve the next available Opus-encoded audio data
    if (!wake_word_opus_.empty()) {
        // Move the data to avoid unnecessary copies
        opus.swap(wake_word_opus_.front());
        wake_word_opus_.pop_front();

        // Return true if the data is non-empty (not the sentinel empty vector)
        return !opus.empty();
    }

    return false;
}

