void InitializeButtons()
{
    // Configure the boot button GPIO as an input with internal pull-up resistor
    boot_button_.SetMode(Button::MODE_PULL_UP);

    // Register a callback function to handle button press events
    boot_button_.OnPress([](Button* button) {
        // Start timer to detect press duration
        static TickType_t press_start_time = 0;
        press_start_time = xTaskGetTickCount();
    });

    boot_button_.OnRelease([](Button* button) {
        // Calculate press duration
        static TickType_t press_start_time = 0;
        TickType_t press_duration = xTaskGetTickCount() - press_start_time;

        // Convert to milliseconds
        uint32_t press_ms = (press_duration * portTICK_PERIOD_MS);

        // Handle short press (less than 1 second) - enter Wi-Fi configuration mode
        if (press_ms < 1000) {
            // Trigger Wi-Fi configuration mode
            Application::GetInstance()->EnterWifiConfigMode();
        }
        // Handle long press (1 second or more) - toggle chat state
        else {
            // Toggle chat state
            Application::GetInstance()->ToggleChatState();
        }
    });
}

