    // Calculate frequency bin (assuming frequency is normalized between 0 and 0.5)
    // For a normalized frequency f, the corresponding bin is f * window_size
    float frequency_bin = frequency * static_cast<float>(window_size);

    // Compute angular frequency omega = 2 * pi * frequency
    float omega = 2.0f * M_PI * frequency;

    // Store the angular frequency for later use
    // The filter coefficient for Goertzel algorithm is 2 * cos(omega)
    filter_coefficient_ = 2.0f * std::cos(omega);

    // Precompute cosine and sine coefficients for amplitude calculation
    cos_coefficient_ = std::cos(omega);
    sin_coefficient_ = std::sin(omega);

    // Initialize state buffer with appropriate size (at least 2 elements for the filter)
    state_buffer_.clear();
    state_buffer_.resize(2, 0.0f);
