    // Restore the samples back to the buffer
    state_buffer_.push_back(s_minus_1);
    state_buffer_.push_back(s_minus_2);

    // Compute the real and imaginary parts using the Goertzel algorithm
    // Real part: R = s[-1] * cos_coefficient_ - s[-2] * sin_coefficient_
    float real_part = s_minus_1 * cos_coefficient_ - s_minus_2 * sin_coefficient_;

    // Imaginary part: I = s[-1] * sin_coefficient_ + s[-2] * cos_coefficient_
    float imaginary_part = s_minus_1 * sin_coefficient_ + s_minus_2 * cos_coefficient_;

    // Calculate amplitude: amplitude = sqrt(real^2 + imaginary^2)
    float amplitude = std::sqrt(real_part * real_part + imaginary_part * imaginary_part);

    // Normalize by half the window size as per the requirement
    amplitude /= (static_cast<float>(window_size_) / 2.0f);

    return amplitude;
}

