    for (float probability : probabilities)
    {
        // Convert probability to binary bit based on threshold
        uint8_t bit = (probability > threshold) ? 1 : 0;

        // Add bit to identifier buffer
        identifier_buffer_.push_back(bit);

        // Keep identifier buffer size within bounds
        if (identifier_buffer_.size() > identifier_buffer_size_)
        {
            identifier_buffer_.pop_front();
        }

        // Check if we're in waiting state and looking for start identifier
        if (current_state_ == DataReceptionState::kWaiting)
        {
            // Check if we've matched the start identifier
            if (identifier_buffer_.size() >= start_of_transmission_.size())
            {
                bool match = true;
                for (size_t i = 0; i < start_of_transmission_.size(); ++i)
                {
                    if (identifier_buffer_[identifier_buffer_.size() - start_of_transmission_.size() + i] != 
                        start_of_transmission_[i])
                    {
                        match = false;
                        break;
                    }
                }

                if (match)
                {
                    // Found start identifier, transition to receiving state
                    current_state_ = DataReceptionState::kReceiving;
                    // Clear the bit buffer as we're starting fresh
                    bit_buffer_.clear();
                    // Remove the start identifier from the identifier buffer
                    while (identifier_buffer_.size() > start_of_transmission_.size())
                    {
                        identifier_buffer_.pop_front();
                    }
                }
            }
        }
        // Check if we're in receiving state and looking for end identifier
        else if (current_state_ == DataReceptionState::kReceiving)
        {
            // Add bit to main bit buffer
            bit_buffer_.push_back(bit);

            // Check if we've reached maximum buffer size
            if (bit_buffer_.size() >= max_bit_buffer_size_)
            {
                // Buffer overflow, reset and go back to inactive
                ClearBuffers();
                current_state_ = DataReceptionState::kInactive;
                return false;
            }

            // Check if we've matched the end identifier
            if (identifier_buffer_.size() >= end_of_transmission_.size())
            {
                bool match = true;
                for (size_t i = 0; i < end_of_transmission_.size(); ++i)
                {
                    if (identifier_buffer_[identifier_buffer_.size() - end_of_transmission_.size() + i] != 
                        end_of_transmission_[i])
                    {
                        match = false;
                        break;
                    }
                }

                if (match)
                {
                    // Found end identifier, process the received data
                    // Convert bits to bytes
                    std::vector<uint8_t> bytes = ConvertBitsToBytes(bit_buffer_);

                    // Convert to string
                    std::string received_text(reinterpret_cast<char*>(bytes.data()), bytes.size());

                    // Optional checksum validation
                    if (enable_checksum_validation_ && received_text.length() >= 1)
