                        // Extract checksum (last byte)
                        uint8_t received_checksum = static_cast<uint8_t>(received_text.back());

                        // Calculate expected checksum (excluding the checksum byte itself)
                        std::string data_without_checksum = received_text.substr(0, received_text.length() - 1);
                        uint8_t calculated_checksum = CalculateChecksum(data_without_checksum);

                        // Validate checksum
                        if (received_checksum != calculated_checksum)
                        {
                            // Checksum mismatch, clear buffers and return false
                            ClearBuffers();
                            current_state_ = DataReceptionState::kInactive;
                            return false;
                        }
                    }

                    // Valid data received
                    decoded_text = std::move(received_text);
                    ClearBuffers();
                    current_state_ = DataReceptionState::kInactive;
                    return true;
                }
            }
        }
        // If we're in inactive state, look for start identifier
        else if (current_state_ == DataReceptionState::kInactive)
        {
            if (identifier_buffer_.size() >= start_of_transmission_.size())
            {
                bool match = true;
                for (size_t i = 0; i < start_of_transmission_.size(); ++i)
                {
