void Backlight::OnTransitionTimer() {
    // Update current brightness towards target
    brightness_ += step_;

    // Check if we've reached or exceeded the target brightness
    bool reached_target = false;
    if (step_ > 0) {
        // Increasing brightness - check if we've reached or passed target
        reached_target = (brightness_ >= target_brightness_);
    } else {
        // Decreasing brightness - check if we've reached or dropped below target
        reached_target = (brightness_ <= target_brightness_);
    }

    // If target is reached, stop the timer
    if (reached_target) {
        brightness_ = target_brightness_;
        esp_timer_stop(transition_timer_);
    }

    // Apply the updated brightness to hardware
    SetBrightnessImpl(brightness_);
}

