    err = nvs_open(NVS_NAMESPACE, NVS_READWRITE, &nvs_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open NVS: %s", esp_err_to_name(err));
        uuid_ = GenerateUuid();
        return;
    }

    // Check if UUID exists
    size_t uuid_len = 0;
    err = nvs_get_str(nvs_handle, "uuid", nullptr, &uuid_len);

    if (err == ESP_OK && uuid_len > 0) {
        // UUID exists, load it
        char* uuid_buffer = new char[uuid_len];
        err = nvs_get_str(nvs_handle, "uuid", uuid_buffer, &uuid_len);
        if (err == ESP_OK) {
            uuid_ = std::string(uuid_buffer);
            delete[] uuid_buffer;

            // Validate UUID format (basic check)
            if (uuid_.length() != 36) {
