            uuid_ = GenerateUuid();
            err = nvs_set_str(nvs_handle, "uuid", uuid_.c_str());
            if (err != ESP_OK) {
                ESP_LOGE(TAG, "Failed to save UUID: %s", esp_err_to_name(err));
