std::string Board::GetSystemInfoJson() {
    cJSON *json = cJSON_CreateObject();
    if (!json) {
        return "";
    }

    // Hardware information
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);

    cJSON_AddStringToObject(json, "chip_model", 
        chip_info.model == CHIP_ESP32 ? "ESP32" : 
        chip_info.model == CHIP_ESP32S2 ? "ESP32-S2" : 
        chip_info.model == CHIP_ESP32S3 ? "ESP32-S3" : 
        chip_info.model == CHIP_ESP32C3 ? "ESP32-C3" : "Unknown");

    cJSON_AddNumberToObject(json, "cores", chip_info.cores);
    cJSON_AddNumberToObject(json, "revision", chip_info.revision);

    // Flash size
    size_t flash_size = 0;
    if (esp_flash_get_size(NULL, &flash_size) == ESP_OK) {
        cJSON_AddNumberToObject(json, "flash_size_bytes", flash_size);
    }

    // MAC address
    uint8_t mac[6];
    if (esp_efuse_mac_get_default(mac) == ESP_OK) {
        char mac_str[18];
        snprintf(mac_str, sizeof(mac_str), "%02X:%02X:%02X:%02X:%02X:%02X",
                 mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
        cJSON_AddStringToObject(json, "mac_address", mac_str);
    }

    // Application metadata
    auto app_desc = esp_app_get_description();
    if (app_desc) {
        cJSON_AddStringToObject(json, "app_name", app_desc->project_name);
        cJSON_AddStringToObject(json, "app_version", app_desc->version);
        cJSON_AddStringToObject(json, "compile_time", app_desc->date);
    }

    // Partition information
    const esp_partition_t *running_partition = esp_ota_get_running_partition();
    if (running_partition) {
        cJSON_AddStringToObject(json, "partition_label", running_partition->label);
        cJSON_AddNumberToObject(json, "partition_size", running_partition->size);
        cJSON_AddNumberToObject(json, "partition_address", running_partition->address);
    }

    // Runtime information
    cJSON_AddNumberToObject(json, "min_free_heap_size", esp_get_minimum_free_heap_size());
    cJSON_AddNumberToObject(json, "current_free_heap_size", esp_get_free_heap_size());

    // Unique identifier
    cJSON_AddStringToObject(json, "uuid", uuid_.c_str());

    // Board type
    cJSON_AddStringToObject(json, "board_type", GetBoardType().c_str());

    // Serialize to string
    char *json_string = cJSON_Print(json);
    if (json_string) {
        std::string result = json_string;
        cJSON_Free(json_string);
        cJSON_Delete(json);
        return result;
    }

    cJSON_Delete(json);
    return "";
}

