void WifiBoard::TryWifiConnect()
{
    auto &wifi_manager = WifiManager::GetInstance();

    // Check if there are any stored SSIDs
    auto ssids = wifi_manager.GetStoredSsids();

    if (ssids.empty()) {
        // No SSIDs configured, delay briefly then enter config mode
        ESP_LOGI(TAG, "No WiFi credentials found, entering config mode");

        // Schedule config mode entry after a brief delay to allow system to stabilize
        xTaskCreate([](void *arg)
                    {
                        // Small delay to ensure system is ready
                        vTaskDelay(pdMS_TO_TICKS(100));

                        auto *board = static_cast<WifiBoard*>(arg);
                        board->StartWifiConfigMode();

                        vTaskDelete(NULL);
                    }, "wifi_config_delay", 2048, this, 2, NULL);
    } else {
        // We have SSIDs, try to connect
        ESP_LOGI(TAG, "Attempting to connect with stored WiFi credentials");

        // Start connection attempt
        wifi_manager.StartStation();

        // Start connection timeout timer
        esp_timer_start_once(connect_timer_, CONNECT_TIMEOUT_SEC * 1000000ULL);
    }
}

