    // Validate the current device state to ensure it's safe to enter Wi-Fi configuration mode
    if (in_config_mode_) {
        ESP_LOGW(TAG, "Already in Wi-Fi configuration mode");
        return;
    }

    // Gracefully shut down active audio and communication processes to avoid conflicts during configuration
    auto& app = Application::GetInstance();
    auto& board = Board::GetInstance();

    // Stop any ongoing audio processing
    auto codec = board.GetAudioCodec();
    if (codec) {
        codec->Stop();
    }

    // Stop AFSK demodulation if running
    AfskDemod::GetInstance().Stop();

    // Stop any active network connections
    WifiManager::GetInstance().StopStation();

    // Display a notification to the user indicating that the device is transitioning to Wi-Fi configuration mode
    app.Alert(Lang::Strings::WIFI_CONFIG_MODE, 
              Lang::Strings::WIFI_CONFIG_MODE_HINT, 
              "gear", 
              Lang::Sounds::OGG_WIFICONFIG);

    // Reset network interfaces and prepare the system for new Wi-Fi settings
    // This is handled by calling StartWifiConfigMode which does all the necessary setup
    StartWifiConfigMode();
}

