const char *WifiBoard::GetNetworkStateIcon()
{
    auto &wifi_manager = WifiManager::GetInstance();

    // Check if in configuration mode
    if (in_config_mode_ || wifi_manager.IsConfigMode())
    {
        return FONT_AWESOME_WIFI_SLASH;
    }

    // Check connection status
    if (!wifi_manager.IsConnected())
    {
        return FONT_AWESOME_WIFI_EXCLAMATION;
    }

    // Device is connected, check signal strength
    int rssi = wifi_manager.GetRssi();

    // Classify signal strength:
    // Strong: >= -60 dBm
    // Fair: >= -70 dBm and < -60 dBm  
    // Weak: < -70 dBm
    if (rssi >= -60)
    {
        return FONT_AWESOME_WIFI;
    }
    else if (rssi >= -70)
    {
        return FONT_AWESOME_WIFI_HALF;
    }
    else
    {
        return FONT_AWESOME_WIFI_QUARTER;
    }
}

