std::string WifiBoard::GetBoardJson() {
    auto& wifi = WifiManager::GetInstance();
    auto root = cJSON_CreateObject();

    // Add board type
    cJSON_AddStringToObject(root, "type", GetBoardType().c_str());

    // Add board name (using the board instance)
    auto& board = Board::GetInstance();
    cJSON_AddStringToObject(root, "name", "wifi_board");

    // Add MAC address
    cJSON_AddStringToObject(root, "mac_address", SystemInfo::GetMacAddress().c_str());

    // Conditionally add Wi-Fi details if not in configuration mode
    if (!wifi.IsConfigMode()) {
        // Add SSID
        cJSON_AddStringToObject(root, "ssid", wifi.GetSsid().c_str());

        // Add RSSI
        int rssi = wifi.GetRssi();
        cJSON_AddNumberToObject(root, "rssi", rssi);

        // Add channel (if available)
        int channel = wifi.GetChannel();
        if (channel > 0) {
            cJSON_AddNumberToObject(root, "channel", channel);
        }

        // Add IP address if connected
        if (wifi.IsConnected()) {
            auto ip_info = wifi.GetIpInfo();
            if (ip_info.ip.addr != 0) {
                char ip_str[16];
                sprintf(ip_str, "%d.%d.%d.%d", 
                        (ip_info.ip.addr >> 0) & 0xFF,
                        (ip_info.ip.addr >> 8) & 0xFF,
                        (ip_info.ip.addr >> 16) & 0xFF,
                        (ip_info.ip.addr >> 24) & 0xFF);
                cJSON_AddStringToObject(root, "ip_address", ip_str);
            }
        }
    }

    // Serialize to string
    char* json_str = cJSON_PrintUnformatted(root);
    std::string result(json_str);
    cJSON_free(json_str);
    cJSON_Delete(root);

    return result;
}

