void WifiBoard::SetPowerSaveLevel(PowerSaveLevel level)
{
    auto &wifi_manager = WifiManager::GetInstance();

    switch (level) {
        case PowerSaveLevel::LOW_POWER:
            // Set Wi-Fi to maximum power saving mode
            wifi_manager.SetPowerSave(WifiPowerSave::MAX_POWER_SAVING);
            break;
        case PowerSaveLevel::BALANCED:
            // Set Wi-Fi to balanced power saving mode
            wifi_manager.SetPowerSave(WifiPowerSave::BALANCED);
            break;
        case PowerSaveLevel::PERFORMANCE:
            // Disable power saving for maximum performance
            wifi_manager.SetPowerSave(WifiPowerSave::NONE);
            break;
        default:
            // Default to balanced if unknown level
            wifi_manager.SetPowerSave(WifiPowerSave::BALANCED);
            break;
    }
}

