void SingleLed::OnBlinkTimer() {
    std::lock_guard<std::mutex> lock(mutex_);

    // Toggle LED state
    if (blink_counter_ > 0) {
        // Alternate between on and off states
        if (blink_counter_ % 2 == 0) {
            // Turn on the LED
            led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
            led_strip_refresh(led_strip_);
        } else {
            // Turn off the LED
            led_strip_clear(led_strip_);
        }

        // Decrement the counter
        blink_counter_--;

        // Check if blinking is complete
        if (blink_counter_ <= 0) {
            // Stop the timer when blinking is complete
            esp_timer_stop(blink_timer_);
        }
    }
}

