void SingleLed::OnStateChanged() {
    // Get the current device state from the application
    DeviceState state = Application::GetInstance().GetDeviceState();

    std::lock_guard<std::mutex> lock(mutex_);

    // Clear any existing blinking
    esp_timer_stop(blink_timer_);

    switch (state) {
        case kDeviceStateUnknown:
        case kDeviceStateIdle:
            // Solid blue for idle/unknown state
            SetColor(0, 0, 255);  // Blue
            TurnOn();
            break;

        case kDeviceStateConnecting:
            // Slow blinking blue for connecting
            SetColor(0, 0, 255);  // Blue
            StartContinuousBlink(500);  // 500ms interval
            break;

        case kDeviceStateListening:
            // Fast blinking cyan for listening
            SetColor(0, 255, 255);  // Cyan
            StartContinuousBlink(200);  // 200ms interval
            break;

        case kDeviceStateSpeaking:
            // Fast blinking red for speaking
            SetColor(255, 0, 0);  // Red
            StartContinuousBlink(150);  // 150ms interval
            break;

        case kDeviceStateWifiConfiguring:
            // Rapid blinking yellow for WiFi configuration
            SetColor(255, 255, 0);  // Yellow
            StartContinuousBlink(100);  // 100ms interval
            break;

        case kDeviceStateUpgrading:
            // Alternating green and blue for upgrade
            SetColor(0, 255, 0);  // Green
            Blink(4, 200);  // 4 blinks, 200ms interval
            break;

        case kDeviceStateActivating:
            // Alternating purple and white for activation
            SetColor(255, 0, 255);  // Purple
            Blink(6, 150);  // 6 blinks, 150ms interval
            break;

        default:
            // Default to off for unknown states
            TurnOff();
            break;
    }
}

