bool MqttProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet)
{
    if (!IsAudioChannelOpened()) {
        ESP_LOGE(TAG, "Audio channel is not opened");
        return false;
    }

    // Prepare the encrypted packet
    size_t payload_size = packet->payload.size();
    if (payload_size == 0) {
        ESP_LOGW(TAG, "Empty audio packet");
        return false;
    }

    // Generate nonce with packet size, timestamp, and sequence number
    // Based on the UDP packet format in OpenAudioChannel, we need:
    // |type 1u|flags 1u|payload_len 2u|ssrc 4u|timestamp 4u|sequence 4u|
    // But since we're generating our own nonce, we'll use the packet metadata
    uint8_t nonce[16];
    memset(nonce, 0, sizeof(nonce));

    // Pack the nonce with packet size, timestamp, and sequence number
    // Using the same format as in the UDP packet parsing
    uint32_t packet_size = static_cast<uint32_t>(payload_size);
    uint32_t timestamp = packet->timestamp;
    uint32_t sequence = ++local_sequence_;

    // Copy size (2 bytes), timestamp (4 bytes), sequence (4 bytes) into nonce
    memcpy(nonce, &packet_size, 2);
    memcpy(nonce + 2, &timestamp, 4);
    memcpy(nonce + 6, &sequence, 4);

    // Encrypt the payload using AES-CTR
    size_t encrypted_size = payload_size;
    size_t nc_off = 0;
    uint8_t stream_block[16] = {0};
    std::vector<uint8_t> encrypted_payload(encrypted_size);

    int ret = mbedtls_aes_crypt_ctr(&aes_ctx_, encrypted_size, &nc_off, nonce, stream_block, 
                                   packet->payload.data(), encrypted_payload.data());
    if (ret != 0) {
        ESP_LOGE(TAG, "Failed to encrypt audio data, ret: %d", ret);
        return false;
    }

    // Create the final UDP packet with header
    // Based on the UDP packet format in OpenAudioChannel, we have:
    // |type 1u|flags 1u|payload_len 2u|ssrc 4u|timestamp 4u|sequence 4u|payload payload_len|
    std::vector<uint8_t> udp_packet(16 + encrypted_size);  // 16 = header size
    uint8_t* ptr = udp_packet.data();

    // Type field (0x01 for audio)
    *ptr++ = 0x01;

    // Flags field
    *ptr++ = 0x00;

    // Payload length (network byte order)
    uint16_t net_payload_len = htons(static_cast<uint16_t>(encrypted_size));
    memcpy(ptr, &net_payload_len, 2);
    ptr += 2;

    // SSRC (using zero for now, could be derived from session)
    uint32_t ssrc = 0;
    uint32_t net_ssrc = htonl(ssrc);
    memcpy(ptr, &net_ssrc, 4);
    ptr += 4;

    // Timestamp (network byte order)
    uint32_t net_timestamp = htonl(timestamp);
    memcpy(ptr, &net_timestamp, 4);
    ptr += 4;

    // Sequence number (network byte order)
    uint32_t net_sequence = htonl(sequence);
    memcpy(ptr, &net_sequence, 4);
    ptr += 4;

    // Encrypted payload
    memcpy(ptr, encrypted_payload.data(), encrypted_size);

    // Send over UDP in a thread-safe manner
    {
        std::lock_guard<std::mutex> lock(channel_mutex_);
        if (udp_ == nullptr) {
            ESP_LOGE(TAG, "UDP socket is null");
            return false;
        }

        if (!udp_->Send((const char*)udp_packet.data(), udp_packet.size())) {
            ESP_LOGE(TAG, "Failed to send audio packet over UDP");
            return false;
        }
    }

    return true;
}

