std::string MqttProtocol::DecodeHexString(const std::string &hex_string)
{
    std::string result;

    // Process the hex string two characters at a time
    for (size_t i = 0; i < hex_string.length(); i += 2)
    {
        // Check if we have at least two characters left
        if (i + 1 < hex_string.length())
        {
            char high_char = hex_string[i];
            char low_char = hex_string[i + 1];

            // Convert each hex character to its numeric value
            uint8_t high_nibble = CharToHex(high_char);
            uint8_t low_nibble = CharToHex(low_char);

            // Combine into a single byte
            uint8_t byte_value = (high_nibble << 4) | low_nibble;

            // Append to result
            result.push_back(static_cast<char>(byte_value));
        }
        else
        {
            // Handle odd-length input - skip the last character or treat as 0
            // Based on typical hex decoding behavior, we ignore incomplete pairs
            break;
        }
    }

    return result;
}

