bool WebsocketProtocol::OpenAudioChannel()
{
    // Check if already connected
    if (IsAudioChannelOpened())
    {
        return true;
    }

    // Create WebSocket instance
    websocket_ = std::make_unique<WebSocket>();

    // Configure WebSocket connection parameters
    WebSocket::Config config;
    config.url = server_url_;
    config.headers["Authorization"] = "Bearer " + auth_token_;
    config.headers["X-Device-ID"] = device_id_;
    config.headers["X-Device-Model"] = device_model_;
    config.headers["X-Protocol-Version"] = std::to_string(version_);

    // Set up binary protocol handler for different versions
    if (version_ == 2)
    {
        config.binary_handler = [this](const uint8_t* data, size_t length) {
            if (length < sizeof(BinaryProtocol2))
                return;

            auto bp2 = (const BinaryProtocol2*)data;
            uint16_t version = ntohs(bp2->version);
            uint32_t timestamp = ntohl(bp2->timestamp);
            uint32_t payload_size = ntohl(bp2->payload_size);

            if (length < sizeof(BinaryProtocol2) + payload_size)
                return;

            // Process audio packet
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->timestamp = timestamp;
            packet->payload.assign(bp2->payload, bp2->payload + payload_size);

            if (on_incoming_audio_)
            {
                on_incoming_audio_(std::move(packet));
            }
        };
    }
    else if (version_ == 3)
    {
        config.binary_handler = [this](const uint8_t* data, size_t length) {
            if (length < sizeof(BinaryProtocol3))
                return;

            auto bp3 = (const BinaryProtocol3*)data;
            uint16_t payload_size = ntohs(bp3->payload_size);

            if (length < sizeof(BinaryProtocol3) + payload_size)
                return;

            // Process audio packet
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->payload.assign(bp3->payload, bp3->payload + payload_size);

            if (on_incoming_audio_)
            {
                on_incoming_audio_(std::move(packet));
            }
        };
    }
    else
    {
        config.binary_handler = [this](const uint8_t* data, size_t length) {
            // Handle raw binary data
            auto packet = std::make_unique<AudioStreamPacket>();
            packet->payload.assign(data, data + length);

            if (on_incoming_audio_)
            {
                on_incoming_audio_(std::move(packet));
            }
        };
    }

