    config.text_handler = [this](const std::string& text) {
        cJSON *root = cJSON_Parse(text.c_str());
        if (root == nullptr)
            return;

        if (on_incoming_json_)
        {
            on_incoming_json_(root);
        }

        cJSON_Delete(root);
    };

    // Connect to WebSocket
    if (!websocket_->Connect(config))
    {
        ESP_LOGE(TAG, "Failed to connect to WebSocket");
        websocket_.reset();
        return false;
    }

