    std::string hello_message = GetHelloMessage();
    if (!SendText(hello_message))
    {
        ESP_LOGE(TAG, "Failed to send hello message");
        websocket_.reset();
        return false;
    }

    // Wait for server hello response
    EventBits_t bits = xEventGroupWaitBits(event_group_handle_, 
                                          WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT,
                                          pdTRUE, pdFALSE, pdMS_TO_TICKS(5000));

    if (!(bits & WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT))
    {
        ESP_LOGE(TAG, "Timeout waiting for server hello");
        websocket_.reset();
        return false;
    }

    // Set up connection callbacks
    websocket_->OnConnected([this]() {
        if (on_connected_)
        {
            on_connected_();
        }
    });

    websocket_->OnDisconnected([this]() {
        if (on_disconnected_)
        {
            on_disconnected_();
        }
        CloseAudioChannel();
    });

    // Set up audio channel opened callback
    if (on_audio_channel_opened_)
    {
        on_audio_channel_opened_();
    }

    return true;
}

