{
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        return false;
    }

    if (!websocket_->Send(text))
    {
        ESP_LOGE(TAG, "Failed to send text: %s", text.c_str());
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    return true;
}

